import{_ as e,o as r,c as i,a2 as t}from"./chunks/framework.BFZItJIV.js";const p=JSON.parse('{"title":"S3 For XunRuiCMSについて","description":"","frontmatter":{},"headers":[],"relativePath":"ja/about.md","filePath":"ja/about.md","lastUpdated":1778063279000}'),l={name:"ja/about.md"};function o(n,a,s,h,u,c){return r(),i("div",null,[...a[0]||(a[0]=[t('<h1 id="s3-for-xunruicmsについて" tabindex="-1">S3 For XunRuiCMSについて <a class="header-anchor" href="#s3-for-xunruicmsについて" aria-label="Permalink to &quot;S3 For XunRuiCMSについて&quot;">​</a></h1><h2 id="プロジェクト概要" tabindex="-1">プロジェクト概要 <a class="header-anchor" href="#プロジェクト概要" aria-label="Permalink to &quot;プロジェクト概要&quot;">​</a></h2><p>S3 For XunRuiCMSは、AWS S3 のクラou user</p><h1 id="关于-s3-for-xunruicms" tabindex="-1">关于 S3 For XunRuiCMS <a class="header-anchor" href="#关于-s3-for-xunruicms" aria-label="Permalink to &quot;关于 S3 For XunRuiCMS&quot;">​</a></h1><h2 id="项目简介" tabindex="-1">项目简介 <a class="header-anchor" href="#项目简介" aria-label="Permalink to &quot;项目简介&quot;">​</a></h2><p>S XunRuiCMS系统提供 AWS S3 云存储支持的插件。</p><h2 id="功能特性" tabindex="-1">功能特性 <a class="header-anchor" href="#功能特性" aria-label="Permalink to &quot;功能特性&quot;">​</a></h2><ul><li>完整的文件上传For下载管理功能</li><li>支持大文件 For片上传和断 For续传</li><li>与迅睿CMS文件管理系统无缝集成</li><li>完善的错误处理和 日志记录</li></ul><h2 id="安装要求" tabindex="-1">安装要求 <a class="header-anchor" href="#安装要求" aria-label="Permalink to &quot;安装要求&quot;">​</a></h2><ul><li>PHP 74 或更高版本</li></ul><p>迅睿CMSプラグイン市場からインストール</p><h2 id="使用方法" tabindex="-1">使用方法 <a class="header-anchor" href="#使用方法" aria-label="Permalink to &quot;使用方法&quot;">​</a></h2><ol><li>プラグインをインストール後、迅睿CMS後台でAWS S3に関する情報を設定します。</li><li>プラグイン有効後、迅睿CMSファイル管理でAWS S3を使用してストレージを行えます。</li></ol><h2 id="文書サイトの技術スタック" tabindex="-1">文書サイトの技術スタック <a class="header-anchor" href="#文書サイトの技術スタック" aria-label="Permalink to &quot;文書サイトの技術スタック&quot;">​</a></h2><p>この文書サイトは次の技術で構築されています：</p><p><strong>VitePress</strong> - スタティックサイトジェネレーター、バージョン ^1.0.0</p><ul><li>公式サイト：<a href="https://vitepress.dev/" target="_blank" rel="noreferrer">https://vitepress.dev/</a></li><li>ライセンス：MIT License</li></ul><p><strong>vitepress-plugin-image-viewer</strong> - 画像ビューワー用プラグイン、バージョン ^1.1.6</p><ul><li>公式サイト：<a href="https://github.com/noonnightrocker/vitepress-plugin-image-viewer" target="_blank" rel="noreferrer">https://github.com/noonnightrocker/vitepress-plugin-image-viewer</a></li><li>ライセンス：MIT License</li></ul><h2 id="その他のお礼" tabindex="-1">その他のお礼 <a class="header-anchor" href="#その他のお礼" aria-label="Permalink to &quot;その他のお礼&quot;">​</a></h2><p>Vue.js、Vite、VitePress などのオープンソースプロジェクトの contributers に感謝します。</p><h2 id="作者情報" tabindex="-1">作者情報 <a class="header-anchor" href="#作者情報" aria-label="Permalink to &quot;作者情報&quot;">​</a></h2><ul><li>作者：陈延德</li><li>邮箱：<a href="mailto:me@chenyande.com" target="_blank" rel="noreferrer">me@chenyande.com</a></li><li>站点：<a href="https://www.chenyande.com" target="_blank" rel="noreferrer">chenyande.com</a></li></ul><h2 id="�-rajasthanicense" tabindex="-1">� Rajasthanicense <a class="header-anchor" href="#�-rajasthanicense" aria-label="Permalink to &quot;� Rajasthanicense&quot;">​</a></h2><p>本プロジェクトは Apache License 2.0 の下で許可されます。</p>',25)])])}const m=e(l,[["render",o]]);export{p as __pageData,m as default};
